#include <iostream>
using namespace std;

int main() {
    auto sum = [](int a, int b) {
        return a + b;
    };
    cout << "Sum: " << sum(5, 3) << endl;
    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int x = 10;
    auto modify = [&x]() {
        x = 20; // Modified original x
    };
    modify();
    cout << "New x: " << x << endl;
    return 0;
}

