#include <iostream>
#include <memory>
using namespace std;

int main() {
    shared_ptr<int> p1 = make_shared<int>(50);
    shared_ptr<int> p2 = p1;
    cout << "Ref count: " << p1.use_count() << endl; // Prints 2
    return 0;
}

#include <iostream>
#include <string>
#include <utility>
using namespace std;

int main() {
    string s1 = "Big String";
    string s2 = move(s1);
    cout << "s2: " << s2 << endl;
    cout << "s1: " << s1 << endl; // s1 is now empty/valid but unspecified
    return 0;
}

